.darma-loader-uiverse-glass-letter-orb__wrapper {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 180px;
  aspect-ratio: 1 / 1;
  font-family: "Jura", sans-serif;
  font-size: 1.6em;
  font-weight: 700;
  border-radius: 50%;
  background-color: #0005;
  user-select: none;
}

.darma-loader-uiverse-glass-letter-orb {
position: absolute;
top: 0;
left: 0;
width: 100%;
aspect-ratio: 1 / 1;
border-radius: inherit;
z-index: 1;

background-color: #c4d0cc22;
backdrop-filter: blur(40px);
-webkit-backdrop-filter: blur(40px);
box-shadow:
0 0 10px 0 #fffa inset,
0 0 12px 4px #238bbb73 inset,
8px 0 8px 0px #fff inset,
-8px 0 16px 2px #000 inset,
0 0 20px 2px #0006,
0 0 24px 4px #000000d8,
0 12px 200px 0px #2effdc9d;
animation: darma-loader-uiverse-glass-letter-orb-rotate-anim 4s linear infinite;
-webkit-animation: darma-loader-uiverse-glass-letter-orb-rotate-anim 4s linear infinite;
}

@keyframes darma-loader-uiverse-glass-letter-orb-rotate-anim {
0% {
transform: rotate(0deg);
}
100% {
transform: rotate(360deg);
}
}
@-webkit-keyframes rotate-anim {
0% {
-webkit-transform: rotate(0deg);
}
100% {
-webkit-transform: rotate(360deg);
}
}

.darma-loader-uiverse-glass-letter-orb__bg-1,
.darma-loader-uiverse-glass-letter-orb__bg-2 {
position: absolute;
top: 0;
left: 0;
width: 100%;
height: 100%;
border-radius: inherit;
opacity: 0.5;
background-color: #482892a1;
filter: blur(40px);
-webkit-filter: blur(40px);
z-index: 0;
animation: darma-loader-uiverse-glass-letter-orb-bg-transform 4s linear infinite;
-webkit-animation: darma-loader-uiverse-glass-letter-orb-bg-transform 4s linear infinite;
}
.darma-loader-uiverse-glass-letter-orb__bg-2 {
background-color: #0c8653;
animation: darma-loader-uiverse-glass-letter-orb-bg-transform 6s linear infinite reverse;
-webkit-animation: darma-loader-uiverse-glass-letter-orb-bg-transform 6s linear infinite reverse;
}

@keyframes darma-loader-uiverse-glass-letter-orb-bg-transform {
0%,
100% {
transform: translate(-80%, 0%);
clip-path: circle(50% at 130% 50%);
}
25% {
transform: translate(0%, -80%);
clip-path: circle(50% at 50% 130%);
}
50% {
transform: translate(80%, 0%);
clip-path: circle(50% at -30% 50%);
}
75% {
transform: translate(0%, 80%);
clip-path: circle(50% at 50% -30%);
}
}
@-webkit-keyframes bg-transform {
0%,
100% {
-webkit-transform: translate(-80%, 0%);
clip-path: circle(50% at 130% 50%);
}
25% {
-webkit-transform: translate(0%, -80%);
clip-path: circle(50% at 50% 130%);
}
50% {
-webkit-transform: translate(80%, 0%);
clip-path: circle(50% at -30% 50%);
}
75% {
-webkit-transform: translate(0%, 80%);
clip-path: circle(50% at 50% -30%);
}
}

.darma-loader-uiverse-glass-letter-orb__letter {
display: inline-block;
opacity: 0.7;
transform: translateY(0);
animation: darma-loader-uiverse-glass-letter-orb-loader-letter-anim 1.8s infinite ease;
-webkit-animation: darma-loader-uiverse-glass-letter-orb-loader-letter-anim 1.8s infinite ease;
z-index: 2;

color: #0004;
text-shadow: 0 -1px 0 #eeffdd;
filter: drop-shadow(0 6px 3px #000);
}

.darma-loader-uiverse-glass-letter-orb__letter:nth-child(1) {
animation-delay: 0s;
-webkit-animation-delay: 0s;
}
.darma-loader-uiverse-glass-letter-orb__letter:nth-child(2) {
animation-delay: 0.1s;
-webkit-animation-delay: 0.1s;
}
.darma-loader-uiverse-glass-letter-orb__letter:nth-child(3) {
animation-delay: 0.2s;
-webkit-animation-delay: 0.2s;
}
.darma-loader-uiverse-glass-letter-orb__letter:nth-child(4) {
animation-delay: 0.3s;
-webkit-animation-delay: 0.3s;
}
.darma-loader-uiverse-glass-letter-orb__letter:nth-child(5) {
animation-delay: 0.4s;
-webkit-animation-delay: 0.4s;
}
.darma-loader-uiverse-glass-letter-orb__letter:nth-child(6) {
animation-delay: 0.5s;
-webkit-animation-delay: 0.5s;
}
.darma-loader-uiverse-glass-letter-orb__letter:nth-child(7) {
animation-delay: 0.6s;
-webkit-animation-delay: 0.6s;
}
.darma-loader-uiverse-glass-letter-orb__letter:nth-child(8) {
animation-delay: 0.7s;
-webkit-animation-delay: 0.7s;
}
.darma-loader-uiverse-glass-letter-orb__letter:nth-child(9) {
animation-delay: 0.8s;
-webkit-animation-delay: 0.8s;
}
.darma-loader-uiverse-glass-letter-orb__letter:nth-child(10) {
animation-delay: 0.9s;
-webkit-animation-delay: 0.9s;
}

@keyframes darma-loader-uiverse-glass-letter-orb-loader-letter-anim {
0%,
100% {
opacity: 0.5;
transform: none;
}
30% {
opacity: 0.5;
transform: translateX(-3px) rotate(-1deg);
}
40% {
opacity: 0.9;
transform: translateX(2px) rotate(3deg) scale(1.06);
}
}
@-webkit-keyframes loader-letter-anim {
0%,
100% {
opacity: 0.5;
transform: none;
}
30% {
opacity: 0.5;
transform: translateX(-3px) rotate(-1deg);
}
40% {
opacity: 0.9;
transform: translateX(2px) rotate(3deg) scale(1.06);
}
}

